import React, { useEffect } from "react";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import "swiper/css/effect-fade";
import "swiper/css/navigation";
import "swiper/css/pagination";
import "./ProductsDetails.css";
import {
  Autoplay,
  EffectCoverflow,
  Navigation,
  Pagination,
} from "swiper/modules";
import { useParams } from "react-router-dom";
import { useQuery } from "@tanstack/react-query";
import Aos from "aos";
import "aos/dist/aos.css";
import Loading from "../Loading/Loading"; // A reusable loading component

function ProductsDetails() {
  const { ProductId } = useParams();

  useEffect(() => {
    Aos.init({ duration: 2000 });
    window.scrollTo(0, 0);
  }, []);

  // Fetch product data
  const {
    data: productData,
    isLoading,
    error,
  } = useQuery({
    queryKey: ["product", ProductId],
    queryFn: () =>
      fetch(`http://127.0.0.1:8000/api/products/${ProductId}`).then((res) =>
        res.json()
      ),
  });

  if (isLoading) {
    return <Loading />;
  }

  if (error) {
    return <p className="error">Error loading product details: {error.message}</p>;
  }

  // Destructure product data
  const { title, Images, description, ingredients, weight, packing } =
    productData || {};

  return (
    <div className="hugy-body">
      <div
        className="border-container"
        data-aos="fade-up"
        data-aos-duration="1000"
      >
        <h1 data-aos="fade-up" data-aos-duration="2700" className="gg">
          {title}
        </h1>
        <Swiper
          className="pd-swiper"
          effect={"coverflow"}
          grabCursor={true}
          centeredSlides={true}
          slidesPerView={"auto"}
          coverflowEffect={{
            rotate: 50,
            stretch: 0,
            depth: 100,
            modifier: 1,
            slideShadows: false,
          }}
          navigation={true}
          autoplay={{
            delay: 3000,
          }}
          rewind={true}
          spaceBetween={10}
          pagination={{
            clickable: true,
            type: "bullets",
          }}
          modules={[EffectCoverflow, Pagination, Navigation, Autoplay]}
        >
          {Images.map((image, index) => (
            <SwiperSlide key={index} className="pd-swiper-slide">
              <img src={image.image} alt={`Slide ${index + 1}`} />
            </SwiperSlide>
          ))}
        </Swiper>
        <div className="background-hugy">
          <section className="products-details-section">
            <p
              className="products-details-text-title"
              data-aos="fade-up"
              data-aos-duration="2000"
            >
              Product Description
            </p>
            <p
              className="products-details-text-info"
              data-aos="fade-up"
              data-aos-duration="2000"
            >
              {description}
            </p>
            <p
              className="products-details-text-title"
              data-aos="fade-up"
              data-aos-duration="2000"
            >
              Product Ingredients
            </p>
            <p
              className="products-details-text-info"
              data-aos="fade-up"
              data-aos-duration="2000"
            >
              {ingredients}
            </p>
            <p
              className="products-details-text-title"
              data-aos="fade-up"
              data-aos-duration="2000"
            >
              Weight
            </p>
            <p
              className="products-details-text-info"
              data-aos="fade-up"
              data-aos-duration="2000"
            >
              {weight}
            </p>
            <p
              className="products-details-text-title"
              data-aos="fade-up"
              data-aos-duration="2000"
            >
              Packing
            </p>
            <p
              className="products-details-text-info"
              data-aos="fade-up"
              data-aos-duration="2000"
            >
              {packing}
            </p>
          </section>
        </div>
      </div>
    </div>
  );
}

export default ProductsDetails;
